	.SBTTL	INTROCLICPOBCLICX=	118		; bullePOBCLICY=	21LGBCLICX=	283LGBCLICY=	85;--------\\; CLIC    >;========/CLIC:	LOAD.L	A3,#R16"TXIMAS3	CALL	AFIMAGE	JUMP,NE 90$	CALL	CLRFIFO		; vide le FIFO du clavier	CLR.B	D0		; D0 <-- carrs cliqus10$:	LIB	?GETCAR		; attend souris ...	COMP.W	D3,#KEYMGR	JUMP,EQ 10$	COMP.W	D3,#KEYMMR	JUMP,EQ 10$	COMP.W	D3,#KEYMDR	JUMP,EQ 10$	COMP.W	D3,#KEYMGP	JUMP',EQ 20$	COMP.W	D3,#KEYMMP	JUMP',EQ 20$	COMP.W	D3,#KEYMDP	JUMP',EQ 20$;;?	LOAD.B	D3,#BIPERR;;?	.W	LIB,?BEEP	JUMP	10$16$:	LOAD.B	D3,#BIPERR	LIB	?BEEP17$:	CALL	ERRCLIC	JUMP	10$20$:	LOAD.L	A3,#R16"ERCLIC1	LOAD.W	D2,D3		; D2 <-- bouton press	LIB	?IFMOUSE	COMP.W	D4,#50	JUMP,LO 16$	COMP.W	D4,#50+20	JUMP,HS 16$	SWAP.W	D4	CLR.B	D1	LOAD.W	D3,#KEYMGP	LOAD.W	D5,#190	COMP.W	D4,#190	JUMP,LO	16$	COMP.W	D4,#190+20	JUMP,LO	30$	INC.B	D1	LOAD.W	D3,#KEYMMP	LOAD.W	D5,#230	COMP.W	D4,#230	JUMP,LO	16$	COMP.W	D4,#230+20	JUMP,LO	30$	INC.B	D1	LOAD.W	D3,#KEYMDP	LOAD.W	D5,#270	COMP.W	D4,#270	JUMP,LO	16$	COMP.W	D4,#270+20	JUMP,HS 16$30$:	LOAD.L	A3,#R16"ERCLIC2	COMP.W	D3,D2		; clic avec le bon bouton ?	JUMP,NE 16$	TSET.L	D0:D1	JUMP,BS 10$	LOAD.W	D3,D5	SWAP.W	D3	LOAD.W	D3,#51	LOAD.W	D2,#INVDOT	LOAD.W	D5,#8+140$:	PUSH.L	D3	LOAD.W	D4,#18	SWAP.W	D4	LOAD.W	D4,#18	LIB	?DRSEG	POP.L	D3	PUSH.L	D3	ADD.W	D3,#17	LOAD.W	D4,#18	SWAP.W	D4	LOAD.W	D4,#-18	LIB	?DRSEG	POP.L	D3	LOAD.W	D4,#4	NTREL	?DELMS	DEC.W	D5	JUMP,NE 40$	LOAD.L	A3,#R16"ERCLIC4	COMP.B	D0,#B'110	JUMP,EQ 17$	COMP.B	D0,#B'101	JUMP,EQ 17$	COMP.B	D0,#B'011	JUMP,EQ 17$	LOAD.L	A3,#R16"ERCLIC3	COMP.B	D0,#B'111	JUMP,NE 17$	LOAD.B	D3,#BIPDONE	LIB	?BEEP	LOAD.L	A3,#R16"ERCLIC5	CALL	ERRCLIC	LOAD.W	D4,#50*3	NTREL	?DELMS90$:	RET;-----------\\; ERRCLIC    >;-----------/; Affiche un message dans la bulle.; in	A3.L	^message; out	-; mod	D7.WERRCLIC:	PUSHM.L	D2..D4,A3	LOAD.L	D3,#-1	LOAD.L	D4,D3	LIB	?DRMDEF	LOAD.W	D3,#POBCLICY	SWAP.W	D3	LOAD.W	D3,#POBCLICX	LOAD.W	D4,#LGBCLICY	SWAP.W	D4	LOAD.W	D4,#LGBCLICX	LOAD.W	D2,#SETDOT	LIB	?DRMATRIX	; efface la bulle	LIB	?AFTIM	.B	USEGC,GCTBF,GCTBS,GCTBT	.B	MODCAR	.B	PENDOT!CLRDOT	.B	0	.EVEN	ADD.W	D3,#10	SWAP.W	D3	ADD.W	D3,#16	SWAP.W	D340$:	LIB	?SETCURS	SWAP.W	D3	ADD.W	D3,(A0)+ODFCY	SWAP.W	D3	LIB	?AFTEXT	TEST.B	(A3)	JUMP,NE 40$	LIB	?AFTIM	.B	USEGC,GCTXF,GCTXS,GCTXT	.B	MODCAR	.B	SETDOT	.B	0	.EVEN	POPM.L	D2..D4,A3	RETERCLIC1:	.ASCIZ	" "	.ASCIZ	"    Rat !"	.ASCIZ	"    Visez mieux ..."	.ASCIZ	" "	.B	0ERCLIC2:	.ASCIZ	"Vous n'avez pas utilis"	.ASCIZ	"le bon bouton de la"	.ASCIZ	"souris !"	.ASCIZ	"Recommencez ..."	.B	0ERCLIC3:	.ASCIZ	" Trs bien !"	.ASCIZ	" "	.ASCIZ	" Cliquez encore dans"	.ASCIZ	" les carrs restants ..."	.B	0ERCLIC4:	.ASCIZ	" Trs bien !"	.ASCIZ	" "	.ASCIZ	" Cliquez encore dans"	.ASCIZ	" le dernier carr ..."	.B	0ERCLIC5:	.ASCIZ	" "	.ASCIZ	"     C'est parfait !"	.B	0	.EVEN	.END